fn count_chars(s: impl AsRef<str>) -> usize {
    s.as_ref().chars().count()
}

fn word_wrap(text: impl AsRef<str>, width: usize) -> Vec<String> {
    text.as_ref()
        .split_whitespace()
        .fold(vec![String::new()], |mut lines, word| {
            let last = lines.last_mut().unwrap();
            if last.is_empty() {
                last.push_str(word);
            } else if last.len() + 1 + word.len() <= width {
                last.push(' ');
                last.push_str(word);
            } else {
                lines.push(word.to_owned());
            }
            lines
        })
}

fn main() {
    let text = String::from("the quick brown fox jumps over the lazy dog");
    let s: &str = &text; // &str — no .as_ref() needed when passing to AsRef<str> fn
    println!("{}", count_chars(s));     // pass &str directly
    println!("{}", count_chars(&text)); // pass &String directly
    println!("{}", count_chars(text.as_str())); // explicit &str from String
    let wrapped = word_wrap(&text, 15);
    for line in &wrapped { println!("{:?}", line); }
}

