// Or use Cow to avoid allocation when no truncation is needed:
use std::borrow::Cow;
fn truncate_cow<'a>(s: &'a impl AsRef<str>, max: usize) -> Cow<'a, str> {
    let s = s.as_ref();
    if s.len() <= max {
        Cow::Borrowed(s)
    } else {
        Cow::Owned(s[..max].to_owned())
    }
}

fn main() {
    let text = String::from("hello world");
    println!("{}", truncate(&text, 5));         // borrowed
    println!("{}", truncate(&"rust", 10));      // borrowed
    println!("{}", truncate_owned("hello", 3)); // owned
    println!("{}", truncate_cow(&text, 5));     // Cow
}

