use std::collections::HashMap;
use std::borrow::Borrow;
use std::hash::{Hash, Hasher};

struct Ticket(String);

// AsRef: cheap reference conversion, no semantic contract
impl AsRef<str> for Ticket {
    fn as_ref(&self) -> &str { &self.0 }
}

// Borrow: stronger — hash and eq must agree with the owned type
impl Borrow<str> for Ticket {
    fn borrow(&self) -> &str { &self.0 }
}

// Ticket must have the same Hash/Eq as &str for Borrow to be sound:
impl PartialEq for Ticket {
    fn eq(&self, other: &Ticket) -> bool { self.0 == other.0 }
}
impl Eq for Ticket {}
impl Hash for Ticket {
    fn hash<H: Hasher>(&self, state: &mut H) { self.0.hash(state); }
}

fn main() {
    let mut map: HashMap<Ticket, u32> = HashMap::new();
    map.insert(Ticket(String::from("TKT-001")), 42);
    // HashMap::get<Q> where K: Borrow<Q> — look up by &str:
    println!("{:?}", map.get("TKT-001")); // Some(42) — uses Borrow<str>
    // AsRef is fine for simple conversions without the Hash/Eq contract:
    let t = Ticket(String::from("TKT-001"));
    let s: &str = t.as_ref();
    println!("{}", s);
}

