use std::path::{Path, PathBuf};

// Accept a slice of T where T: AsRef<Path>
fn print_paths<T: AsRef<Path>>(paths: &[T]) {
    for p in paths {
        println!("{:?}", p.as_ref());
    }
}

fn longest_path<T: AsRef<Path>>(paths: &[T]) -> Option<&Path> {
    paths.iter()
        .map(AsRef::as_ref)
        .max_by_key(|p| p.components().count())
}

fn main() {
    let paths: Vec<PathBuf> = vec![
        PathBuf::from("/tmp"),
        PathBuf::from("/home/user/documents"),
        PathBuf::from("/etc"),
    ];
    print_paths(&paths);         // Vec<PathBuf>: &[PathBuf], PathBuf: AsRef<Path>
    print_paths(&["/a", "/b"]); // [&str; 2], &str: AsRef<Path>

    if let Some(p) = longest_path(&paths) {
        println!("longest: {:?}", p);
    }
}
